import{_ as i,r as o,o as s,c as r,a as e,b as n,d as c,e as t}from"./app-def54fd2.js";const l="/assets/image-20231220150034474-889ce4b5.png",d={},p=t(`<h1 id="oauth2-client对接认证服务" tabindex="-1"><a class="header-anchor" href="#oauth2-client对接认证服务" aria-hidden="true">#</a> OAuth2 Client对接认证服务</h1><p>项目在初始化时会根据配置的issuer-uri拼接url，即签发地址根目录/.well-known/openid-configuration，像项目中配置的就是该接口会返回认证服务器的元信息。</p><div class="language-web-idl line-numbers-mode" data-ext="web-idl"><pre class="language-web-idl"><code>http<span class="token operator">:</span><span class="token comment">//127.0.0.1:9000/.well-known/openid-configuration</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><img src="`+l+'" alt="image-20231220150034474"></p><h2 id="cookie-问题" tabindex="-1"><a class="header-anchor" href="#cookie-问题" aria-hidden="true">#</a> cookie 问题</h2>',5),h={href:"https://github.com/spring-projects/spring-security/issues/5946",target:"_blank",rel:"noopener noreferrer"},u=t('<p>可以一个使用 192.168.18.14:9001（内网）一个使用 127.0.0.1</p><h2 id="客户端" tabindex="-1"><a class="header-anchor" href="#客户端" aria-hidden="true">#</a> 客户端</h2><p>客户端在oauth2角色解释中是第三方的一个应用，一般会配合资源服务一起使用。</p><p>单体项目</p><ul><li>会同时添加资源服务依赖，客户端负责调用认证服务登录，资源服务器负责解析获取到的token，然后获取token中的权限，目前token中的权限只有scope的权限，并且不太好自定义，所以就需要通过资源服务器配置去更好的解析token。</li></ul><p>分布式项目：</p><ul><li>在网关中添加客户端依赖，检查用户认证信息，由网关代理的微服务添加资源服务依赖，解析网关通过令牌中继的方式携带的access_token；各个微服务添加自己的授权校验。</li><li>在网关中集成客户端依赖，同时集成资源服务依赖，由网关检查用户的认证和授权信息；各个微服务不用添加任何的认证与授权相关的处理，可以直接访问；这种方式需要屏蔽各微服务其它ip的访问，只能由网关代理访问。</li></ul>',7);function _(m,g){const a=o("ExternalLinkIcon");return s(),r("div",null,[p,e("p",null,[n("认证服务器和客户端在同一个机器上时不能使用同一个ip。"),e("a",h,[n("Not able to connect Spring OAuth2 Authorization Server with Client · Issue #5946 · spring-projects/spring-security (github.com)"),c(a)])]),u])}const b=i(d,[["render",_],["__file","OAuth2Client对接认证服务.html.vue"]]);export{b as default};
